const data = items[0].json || {};
const orderItems = Array.isArray(data.items) ? data.items : [];
const rows = orderItems.map(item => `<tr><td>${item.nombre || item.titulo || ''}</td><td>${item.cantidad || 0}</td><td>$${parseFloat(item.precio || 0).toFixed(2)}</td></tr>`).join('');
const html = `<p>Hola ${data.nombre || 'cliente'},</p><p>Gracias por tu compra. Aquí tienes el resumen de tu pedido:</p><table border="1" cellpadding="8" cellspacing="0" style="border-collapse:collapse;width:100%;"><thead><tr><th>Producto</th><th>Cantidad</th><th>Precio</th></tr></thead><tbody>${rows}</tbody></table><p><strong>Total: $${parseFloat(data.total || 0).toFixed(2)}</strong></p><p>Dirección: ${data.direccion || 'No disponible'}</p><p>Gracias por comprar en BeatDrop.</p>`;
const adminHtml = `<p>Nuevo pedido recibido:</p><p><strong>Cliente:</strong> ${data.nombre || 'Cliente'} &lt;${data.email || 'sin-email'}&gt;</p><table border="1" cellpadding="8" cellspacing="0" style="border-collapse:collapse;width:100%;"><thead><tr><th>Producto</th><th>Cantidad</th><th>Precio</th></tr></thead><tbody>${rows}</tbody></table><p><strong>Total:</strong> $${parseFloat(data.total || 0).toFixed(2)}</p>`;
return [{ json: { ...data, html, adminHtml, subjectCustomer: 'Compra confirmada - BeatDrop', subjectAdmin: 'Nuevo pedido en BeatDrop', customerEmail: data.email, adminEmail: data.adminEmail || 'beatdroptfg@gmail.com', textCustomer: `Gracias por tu pedido. Total: $${parseFloat(data.total || 0).toFixed(2)}`, textAdmin: `Nuevo pedido de ${data.nombre || 'Cliente'} - Total $${parseFloat(data.total || 0).toFixed(2)}` } }];
